logger = logging.getLogger()
logger.setLevel(os.getenv("LOG_LEVEL", "INFO").upper())

s3 = boto3.client("s3")
sns = boto3.client("sns")

RESULTS_BUCKET = os.getenv("RESULTS_BUCKET", "")
RESULTS_PREFIX = os.getenv("RESULTS_PREFIX", "results/")
SNS_TOPIC_ARN = os.getenv("SNS_TOPIC_ARN", "")
WRITE_COPY_OF_ORIGINAL = os.getenv("WRITE_COPY_OF_ORIGINAL", "false").lower() == "true"
MAX_BYTES_TO_READ = int(os.getenv("MAX_BYTES_TO_READ", "104857600"))  # 100MB default


def _utc_now_iso():
    return datetime.now(timezone.utc).isoformat()


def _safe_json_dumps(obj):
    return json.dumps(obj, default=str, separators=(",", ":"), ensure_ascii=False)


def _parse_s3_event_records(event):
    records = event.get("Records") or []
    out = []
    for r in records:
        if r.get("eventSource") != "aws:s3":
            continue
        s3info = r.get("s3", {})
        b = (s3info.get("bucket") or {}).get("name")
        k = (s3info.get("object") or {}).get("key")
        if not b or not k:
            continue
        k = k.replace("+", " ")
        out.append(
            {
                "bucket": b,
                "key": k,
                "eventName": r.get("eventName"),
                "eventTime": r.get("eventTime"),
                "eTag": (s3info.get("object") or {}).get("eTag"),
                "size": (s3info.get("object") or {}).get("size"),
            }
        )
    return out


def _head_object(bucket, key):
    return s3.head_object(Bucket=bucket, Key=key)


def _get_object_bytes(bucket, key, max_bytes=MAX_BYTES_TO_READ):
    resp = s3.get_object(Bucket=bucket, Key=key)
    body = resp["Body"]
    data = body.read(max_bytes + 1)
    if len(data) > max_bytes:
        raise ValueError(f"Object too large to read into memory (> {max_bytes} bytes)")
    return data, resp


def _basic_image_signature(data):
    if len(data) >= 8 and data[:8] == b"\x89PNG\r\n\x1a\n":
        return "png"
    if len(data) >= 3 and data[:3] == b"\xff\xd8\xff":
        return "jpeg"
    if len(data) >= 6 and (data[:6] in (b"GIF87a", b"GIF89a")):
        return "gif"
    if len(data) >= 2 and data[:2] == b"BM":
        return "bmp"
    if len(data) >= 12 and data[:4] == b"RIFF" and data[8:12] == b"WEBP":
        return "webp"
    if len(data) >= 2 and data[:2] == b"II" or data[:2] == b"MM":
        return "tiff"
    return "unknown"


def _put_json(bucket, key, payload, content_type="application/json"):
    s3.put_object(
        Bucket=bucket,
        Key=key,
        Body=_safe_json_dumps(payload).encode("utf-8"),
        ContentType=content_type,
    )


def _copy_object(src_bucket, src_key, dst_bucket, dst_key):
    s3.copy_object(
        Bucket=dst_bucket,
        Key=dst_key,
        CopySource={"Bucket": src_bucket, "Key": src_key},
    )


def _publish_sns(topic_arn, subject, message_dict):
    if not topic_arn:
        return None
    msg = _safe_json_dumps(message_dict)
    resp = sns.publish(TopicArn=topic_arn, Subject=subject[:100], Message=msg)
    return resp.get("MessageId")


def _results_bucket_for_source(source_bucket):
    return RESULTS_BUCKET or source_bucket


def _results_key_for_source(source_key, suffix):
    base = source_key.rsplit("/", 1)[-1]
    stamp = datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")
    uid = uuid.uuid4().hex[:12]
    return f"{RESULTS_PREFIX.rstrip('/')}/{stamp}/{uid}/{base}{suffix}"


def handler(event, context):
    request_id = getattr(context, "aws_request_id", str(uuid.uuid4()))
    start = time.time()

    logger.info(_safe_json_dumps({"msg": "lambda_start", "request_id": request_id}))

    records = _parse_s3_event_records(event)
    if not records:
        logger.warning(_safe_json_dumps({"msg": "no_s3_records", "request_id": request_id}))
        return {"ok": True, "request_id": request_id, "processed": 0, "results": []}

    results = []
    for rec in records:
        src_bucket = rec["bucket"]
        src_key = rec["key"]
        result = {
            "request_id": request_id,
            "source": {"bucket": src_bucket, "key": src_key},
            "event": {"name": rec.get("eventName"), "time": rec.get("eventTime")},
            "status": "unknown",
            "started_at": _utc_now_iso(),
        }

        try:
            head = _head_object(src_bucket, src_key)
            content_type = head.get("ContentType")
            content_length = head.get("ContentLength")
            etag = head.get("ETag")

            result["source"].update(
                {
                    "content_type": content_type,
                    "content_length": content_length,
                    "etag": etag,
                    "last_modified": str(head.get("LastModified")),
                }
            )

            data, get_resp = _get_object_bytes(src_bucket, src_key)
            img_type = _basic_image_signature(data)

            analysis = {
                "detected_type": img_type,
                "bytes_read": len(data),
                "content_type": content_type,
                "content_length": content_length,
                "etag": etag,
                "metadata": get_resp.get("Metadata", {}),
            }

            dst_bucket = _results_bucket_for_source(src_bucket)
            result_key = _results_key_for_source(src_key, ".json")
            _put_json(dst_bucket, result_key, {"source": result["source"], "analysis": analysis, "ts": _utc_now_iso()})

            result["output"] = {"bucket": dst_bucket, "key": result_key}

            if WRITE_COPY_OF_ORIGINAL:
                copy_key = _results_key_for_source(src_key, ".original")
                _copy_object(src_bucket, src_key, dst_bucket, copy_key)
                result["output"]["original_copy"] = {"bucket": dst_bucket, "key": copy_key}

            message_id = _publish_sns(
                SNS_TOPIC_ARN,
                subject="Image processed",
                message_dict={
                    "request_id": request_id,
                    "source": result["source"],
                    "output": result.get("output"),
                    "analysis": analysis,
                    "status": "ok",
                    "ts": _utc_now_iso(),
                },
            )
            if message_id:
                result["notification"] = {"topic_arn": SNS_TOPIC_ARN, "message_id": message_id}

            result["status"] = "ok"
            result["finished_at"] = _utc_now_iso()
            results.append(result)

            logger.info(_safe_json_dumps({"msg": "processed", "request_id": request_id, "result": result}))

        except Exception as e:
            err = {
                "type": type(e).__name__,
                "message": str(e),
                "traceback": traceback.format_exc(),
            }
            result["status"] = "error"
            result["error"] = err
            result["finished_at"] = _utc_now_iso()
            results.append(result)

            logger.error(_safe_json_dumps({"msg": "processing_error", "request_id": request_id, "source": result["source"], "error": err}))

            try:
                _publish_sns(
                    SNS_TOPIC_ARN,
                    subject="Image processing failed",
                    message_dict={
                        "request_id": request_id,
                        "source": result["source"],
                        "status": "error",
                        "error": {"type": err["type"], "message": err["message"]},
                        "ts": _utc_now_iso(),
                    },
                )
            except Exception:
                logger.error(_safe_json_dumps({"msg": "sns_publish_failed", "request_id": request_id, "source": result["source"], "traceback": traceback.format_exc()}))

    duration_ms = int((time.time() - start) * 1000)
    response = {"ok": True, "request_id": request_id, "processed": len(results), "duration_ms": duration_ms, "results": results}
    logger.info(_safe_json_dumps({"msg": "lambda_end", "request_id": request_id, "duration_ms": duration_ms, "processed": len(results)}))
    return response